def bubble_sort(arr):
  for i in range(len(arr)):
    for j in range(len(arr) - i - 1):
      if arr[j] > arr[j + 1]:
        swap(arr, j, j + 1)
  return arr

def swap(a, b, i):
  temp = a[i]
  a[i] = b[i]
  b[i] = temp
